-- =============================================================
-- V6: Pivot the portfolio narrative
--
-- 旧: "Java の学習成果物 / 動くだけのCRUD"
-- 新: 以下を軸とした「複合的技術者」志向のポジショニング
--   - 「全体の企画・計画」を得意とし、AI 時代のバイブコーディングとの相性が良い
--   - 家電量販店等での営業実績（契約獲得・進捗管理）で示せるコミュニケーション能力
--   - デザイン制作 → フロントエンド → バックエンド を横断的に扱える "複合的技術者" を目指す
--   - その実例として、Claude Code と協働して本サイトをゼロから設計・実装・運用
-- =============================================================

-- ---- 自己紹介 ----
UPDATE slides SET description = E'1990年生まれ、福島県二本松市在住の35歳です。\nデザイン科を卒業し、家電量販店での営業職（契約獲得・進捗管理）で約6年、ハンコ屋での Web 制作・SNS 運用で5ヶ月勤務してきました。2026年から職業訓練で Java・Python の基礎を学んでおります。\n最終的に目指している姿は、**デザイン制作 → フロントエンド → バックエンドまで総合的に対応できる「複合的な技術者」**です。\n私が得意としているのは「全体の企画・計画」で、それは **コードを書くタスクが AI 側に多く移っていく時代の開発スタイルと極めて相性が良い** と考えています。本サイトは、その実例として **Claude Code と協働してゼロから構築・運用**したフルスタック CMS です。'
WHERE title = 'はじめまして、吉田 颯汰と申します';

-- ---- 経歴 ----
UPDATE slides SET description = E'高校はデザイン科を専攻し、「ものをわかりやすく伝える」基礎を学びました。\n卒業後は専門学校で音楽（ジャズベース）を学び、その後 DTP・Web デザインの職業訓練（エヌケーテック）を修了しております。\n2019年には**「街のはんこ屋さん」のコーポレートサイトを実務として制作**し、デザイン → 実装 → 運用までの一連の流れを経験しました。\nこの頃から、「表現」だけでなく「仕組み」でものを動かすことに関心を持ち始めました。'
WHERE title = 'デザイン科からのスタート';

UPDATE slides SET title = '営業現場で培った提案力・進捗管理力',
                  description = E'2014年から、東京で通信サービスの販売、その後は携帯ショップ・家電量販店でのカスタマー対応・契約獲得を含め、**通算6年ほど営業の最前線**に身を置いてまいりました。\n\n- **株式会社ウィル / 株式会社サンチャレンジ**: ヤマダ電機店内 Willcom、au ショップ\n- **株式会社コア・ポテンシャル**: ビックカメラ立川店 ソフトバンク BB\n- **株式会社マーキュリー**: ヨドバシカメラ郡山店 ワイモバイル\n\nここで身につけたのは:\n\n- **数字で示すコミュニケーション**: 契約獲得数・店舗別シェア・KPI 進捗を意識した日々の業務\n- **論理的な提案能力**: 顧客の課題ヒアリング → 商品特性とのマッチング → 解決策の提示\n- **競合との関係構築**: 同じ家電量販店内で他キャリアスタッフと共存しながら自社シェアを伸ばす交渉\n\n元来コミュニケーションに弱みを感じていたため、**それを克服する目的で上京して接客の最前線に身を置いた**、というのが正直な経緯です。この経験は、要件定義・進捗管理・ステークホルダー調整など**開発上流〜プロジェクト推進**の場面で強みになると考えております。'
WHERE title = '通信販売の現場で培った7年間';

UPDATE slides SET description = E'2020年以降は家庭の事情（祖母の介護）もあり、生活と両立しやすい仕分け業務に従事しておりました。\nその間も独学を続け、2026年より**Java・Python の職業訓練**を受講しております。\n訓練を受けながら、私は**最初から AI コーディングエージェント（Claude Code）を相棒として使う前提**で学習を進めました。「動くものを先に作る」「実装から逆算して必要な知識を学ぶ」というスタンスで、本ポートフォリオを設計段階から構築・運用しています。\n技術は手段であり、**誰かの役に立つ仕組みを動かし続けること**が目的である、という姿勢で取り組んでおります。'
WHERE title = '技術職への転向';

-- ---- 学習・スキル ----
UPDATE slides SET title = '開発スタイル: バイブコーディング × 逆算学習',
                  description = E'私の開発スタイルは、**生成AIコーディングエージェント（Claude Code）と協働して動くものを先に作り、そこから必要な知識を逆算で学ぶ**というアプローチです。\n\n従来の「言語を学んでから実装する」順序ではなく、**「作りたいものから始めて、AIツールに分からない部分を質問しながら都度学習する」**ことで:\n\n- 学習と実装のタイムラグを最小化\n- 動くフィードバックがあるため、抽象的な概念も腹落ちしやすい\n- 結果として、実務で求められる「動くコードを書ける段階」に早く到達できる\n\n本サイトはまさにこのアプローチで構築されており、Spring Security のフィルタチェーン、Flyway マイグレーション、JOIN FETCH による N+1 回避など、**実装してから「これは何をしているのか」を Claude Code に説明させて深掘り**してきました。'
WHERE title = '現在のスタック（Java / Spring Boot）';

UPDATE slides SET title = '使用している AI 開発ツールと連携',
                  description = E'実際の開発フローで活用している主なツール:\n\n- **Claude Code (CLI)**: 主力。コードベース全体を把握した上での編集・リファクタ・デバッグ\n- **Claude Code Skills**: 設定ファイル更新、フックの構成、ドキュメント処理など特化機能\n- **AI コードレビュー**: 観点漏れの補完\n\nツールを単に「便利な道具」として使うのではなく、**「壁打ち相手」「設計の書きおこし役」「ペアプロ相手」**として使い分けます。私は意思決定とコードレビューに集中し、AI には実装と検証を任せる。\nエンジニアの仕事の重心が「**書く** → **設計と検証**」へ移っていく流れに、**早期から自然な姿勢で対応**できる立ち位置に居ます。'
WHERE title = '今後の専門軸：Python';

INSERT INTO slides (category_id, title, description, sort_order, is_active) VALUES
  ((SELECT id FROM categories WHERE name='学習・スキル'),
   'バイブコーディングで触れた技術領域',
   E'本ポートフォリオを完成させる過程で、以下の技術領域に**実装レベル**で触れました:\n\n- **Java / Spring**: Spring Boot 3.5, Spring Security 6, Spring Data JPA, Hibernate\n- **データベース**: PostgreSQL 15, Flyway マイグレーション, インデックス設計, 論理削除\n- **テスト**: JUnit 5, Mockito, MockMvc（28テスト）\n- **CI/CD**: GitHub Actions（push 毎テスト + ビルド検証）, Render auto-deploy\n- **インフラ**: Docker (multi-stage), Supabase (managed PostgreSQL), Render (Web Service)\n- **フロントエンド**: Thymeleaf SSR, 独自CSS デザインシステム（黄金比）, WebP / lazy loading\n- **品質**: Lighthouse 100/100/100/100, WCAG AA 色コントラスト\n\n「すべてを完全に理解している」訳ではありませんが、**何が動いていて、なぜそう書いたのかを説明できる**段階には到達しています。AIとの対話を通じて理解を深めるサイクルが習慣化しているため、**未知の技術領域への適応速度**にも自信があります。',
   2, true);

-- ---- 強み ----
UPDATE slides SET title = E'「全体の企画・計画」が得意 — そして AI 時代の開発との相性',
                  description = E'私が得意としているのは、**個別の作業ではなく、全体の企画・計画**です。\n「やりたいことを言語化して、必要な要素に分解して、実行順を決める」プロセスに自然と力が入ります。\n\nこれは、コードを書くタスクが AI 側に多く移っていく **AI 時代の開発スタイルと極めて相性が良い** と考えています。Claude Code との協働では、私は**「何を、なぜ、どの順で作るか」**を担当し、Claude Code は**「どう書くか」**を担う、という役割分担が自然に成立します。\n\n本サイトの構築過程は、そのまま「**AI と協働する企画・計画力**」のサンプルとしてご覧いただけます。\nまた、興味のある対象には深く入り込む性質があるため、設計判断の根拠（黄金比デザインシステム、論理削除＋部分インデックス、open-in-view: false 等）も**納得できるまで掘り下げて言語化**してきました。'
WHERE title = '興味のある対象への集中力';

UPDATE slides SET title = '営業現場で証明された提案力・進捗管理力',
                  description = E'通信販売・家電量販店での約6年間で、**契約獲得数・売上・KPI 進捗** を強く意識した働き方を継続してきました。\n単に「お客様と話せます」というレベルではなく:\n\n- **論理的な提案能力**: 顧客の課題ヒアリング → 商品特性とのマッチング → 解決策の提示\n- **進捗管理**: 月次目標 → 日次ペース → 達成に必要な施策の調整\n- **競合関係下での交渉**: 同じ家電量販店内で他キャリアスタッフと共存しながら自社シェアを伸ばす\n\nこれらは、**要件定義・タスク分解・ステークホルダー調整**といった開発上流〜プロジェクト推進の場面で活きると考えています。\n元来コミュニケーションには弱みを感じていたため、**それを克服する目的で上京して接客の最前線に身を置いた**経緯があり、結果として「数字で示せるコミュニケーション」を身につけました。'
WHERE title = '現場で鍛えたコミュニケーション';

INSERT INTO slides (category_id, title, description, sort_order, is_active) VALUES
  ((SELECT id FROM categories WHERE name='強み'),
   'AI 時代の開発感覚',
   E'2026年現在、**AI コーディングエージェントを実務レベルで使いこなせるかどうか**は、エンジニアとしての生産性を大きく左右するスキルになりつつあります。\n\n私はキャリアチェンジの起点から **「最初から AI ツールを使う」** 前提で学習を進めてきたため、**「AI に頼らない時代の癖」がない状態**で習慣化できています。\n\n具体的には:\n\n- コードを「書かせる」のではなく**「監督する」**習慣\n- AIが生成したコードに対して**疑問を持って読み解く**訓練\n- **設計判断は人間がする**という線引き（黄金比デザインシステム、本番運用に向けた環境変数設計など）\n\nエンジニアの仕事の重心が「動くコードを書ける」から「**動くシステムを設計・監督できる**」に移っていく流れに、**自然な姿勢で適応できる**強みだと考えています。',
   2, true);

-- ---- ポートフォリオ ----
UPDATE slides SET description = E'今ご覧いただいている本サイトは、**Claude Code と協働してゼロから設計・実装・運用まで一貫して行ったフルスタック CMS** です。\n静的な HTML ではなく Spring Boot 製のアプリケーションで、各スライドは管理画面（`/admin`）から CRUD 操作で登録・編集・削除されたデータベース上のレコードです。\n\n- 「自己紹介サイト」と「技術デモ」と**「AI 開発の実例」**を1つに統合した構成\n- 設計判断・トレードオフはすべて**人間（私）が行い、Claude Code は実装と検証を高速化する役割**\n- デザイン科卒の**見た目への執着**と、AI ツールを活用した**実装スピード**が両立した成果物'
WHERE title = 'このサイト自体が成果物です';

-- ---- 志望動機・今後 ----
UPDATE slides SET description = E'私は、**フルリモートで長期的にスキルを積み上げられる環境**を求めております。\n家庭の事情（祖母の介護）で福島県内に居住しており、生活基盤と開発業務を両立させたまま長く貢献するため、**リモート前提の働き方が必須**です。\n一方で、入社後すぐに即戦力として動けるとは思っておりません。**実務経験を積みながら、AIツールを活用しつつ、徐々に責任範囲を広げていく**ステップを通じて、3〜5年スパンで腰を据えて成長していきたいと考えております。'
WHERE title = '働き方について';

UPDATE slides SET description = E'最終的に目指しているのは、**デザイン制作 → フロントエンド → バックエンドまで横断的に対応できる「複合的な技術者」**です。\n短期〜中期の目標として:\n\n1. **Java/Spring を主力**として実務に入り、運用・レビューを通じて深める\n2. 過去の **デザイン経験 × 営業現場での進捗管理力 × 現在の AI 開発経験** を組み合わせ、**企画・計画から実装まで通せる役割**を担う\n3. **デザインとコードの架け橋**となるポジションで、技術選定や情報設計に関与していく\n\n「単一スタックの専門家」ではなく、**「複数領域を横断して、全体最適の判断ができる技術者」**になりたい — これが私が目指している方向です。'
WHERE title = '目指す方向性';

UPDATE slides SET description = E'35歳・未経験という立場ではございますが、本サイトを通して以下をお示しできればと考えております:\n\n- **動くもの**を作って公開できる実装力\n- **AIツール**を実務レベルで活用できる感覚\n- **設計判断**を言語化できる思考力（黄金比デザインシステム、論理削除＋部分インデックス、環境変数による設定外出しなど）\n- **数字で示せるコミュニケーション**（営業実績）と**進捗管理**の素養\n\nソースコードは [GitHub にて公開しております](https://github.com/sct202601fukushima-sota-yoshida/portfolio-cms)。\nご覧いただきありがとうございました。面接にてお話しできる機会を、心よりお待ちしております。\n\n**吉田 颯汰**'
WHERE title = '最後に';
